  1→import { useCallback, useEffect, useId, useRef, useState } from 'react';
  2→import { FormField } from './form_field';
  3→import './form_tag_picker.scss';
  4→
  5→export interface FormTagPickerOption {
  6→  label: string;
  7→  value: string;
  8→}
  9→
 10→interface FormTagPickerProps {
 11→  label: string;
 12→  value: string[];
 13→  onChange: (value: string[]) => void;
 14→  options: FormTagPickerOption[];
 15→  placeholder?: string;
 16→  description?: string;
 17→  error?: string;
 18→  autoFocus?: boolean;
 19→}
 20→
 21→export function FormTagPicker({
 22→  label,
 23→  value,
 24→  onChange,
 25→  options,
 26→  placeholder,
 27→  description,
 28→  error,
 29→  autoFocus,
 30→}: FormTagPickerProps) {
 31→  const id = useId();
 32→  const listboxId = useId();
 33→  const [query, setQuery] = useState('');
 34→  const [open, setOpen] = useState(false);
 35→  const [activeIndex, setActiveIndex] = useState(0);
 36→  const inputRef = useRef<HTMLInputElement>(null);
 37→  const containerRef = useRef<HTMLDivElement>(null);
 38→  const menuRef = useRef<HTMLUListElement>(null);
 39→
 40→  const availableOptions = options.filter(
 41→    opt =>
 42→      !value.includes(opt.value) &&
 43→      opt.label.toLowerCase().includes(query.toLowerCase()),
 44→  );
 45→
 46→  const resetDropdown = useCallback(() => {
 47→    setOpen(false);
 48→    setQuery('');
 49→    setActiveIndex(0);
 50→  }, []);
 51→
 52→  useEffect(() => {
 53→    setActiveIndex(0);
 54→  }, [query]);
 55→
 56→  useEffect(() => {
 57→    if (!open) return;
 58→    const activeEl = menuRef.current?.querySelector('[data-active="true"]');
 59→    if (activeEl) {
 60→      activeEl.scrollIntoView({ block: 'nearest' });
 61→    }
 62→  }, [
 63→    activeIndex,
 64→    open,
 65→  ]);
 66→
 67→  useEffect(() => {
 68→    function handleClickOutside(e: MouseEvent) {
 69→      if (
 70→        containerRef.current &&
 71→        !containerRef.current.contains(e.target as Node)
 72→      ) {
 73→        resetDropdown();
 74→      }
 75→    }
 76→    if (open) {
 77→      document.addEventListener('mousedown', handleClickOutside);
 78→    }
 79→    return () => document.removeEventListener('mousedown', handleClickOutside);
 80→  }, [
 81→    open,
 82→    resetDropdown,
 83→  ]);
 84→
 85→  const selectOption = useCallback(
 86→    (optionValue: string) => {
 87→      onChange([
 88→        ...value,
 89→        optionValue,
 90→      ]);
 91→      setQuery('');
 92→      setActiveIndex(0);
 93→      inputRef.current?.focus();
 94→    },
 95→    [
 96→      value,
 97→      onChange,
 98→    ],
 99→  );
100→
101→  const removeTag = useCallback(
102→    (optionValue: string) => {
103→      onChange(value.filter(v => v !== optionValue));
104→      inputRef.current?.focus();
105→    },
106→    [
107→      value,
108→      onChange,
109→    ],
110→  );
111→
112→  const handleKeyDown = useCallback(
113→    (e: React.KeyboardEvent) => {
114→      if (e.key === 'Backspace' && !query && value.length > 0) {
115→        onChange(value.slice(0, -1));
116→        return;
117→      }
118→
119→      if (!open || availableOptions.length === 0) {
120→        if (e.key === 'ArrowDown' && !open && availableOptions.length > 0) {
121→          e.preventDefault();
122→          setOpen(true);
123→        }
124→        return;
125→      }
126→
127→      switch (e.key) {
128→        case 'ArrowDown':
129→          e.preventDefault();
130→          setActiveIndex(prev =>
131→            prev < availableOptions.length - 1 ? prev + 1 : 0);
132→          break;
133→        case 'ArrowUp':
134→          e.preventDefault();
135→          setActiveIndex(prev =>
136→            prev > 0 ? prev - 1 : availableOptions.length - 1);
137→          break;
138→        case 'Enter':
139→          e.preventDefault();
140→          e.stopPropagation();
141→          if (availableOptions[activeIndex]) {
142→            selectOption(availableOptions[activeIndex].value);
143→          }
144→          break;
145→        case 'Escape':
146→          e.preventDefault();
147→          e.stopPropagation();
148→          resetDropdown();
149→          break;
150→        case 'Tab':
151→          resetDropdown();
152→          break;
153→      }
154→    },
155→    [
156→      open,
157→      query,
158→      value,
159→      onChange,
160→      availableOptions,
161→      activeIndex,
162→      selectOption,
163→      resetDropdown,
164→    ],
165→  );
166→
167→  const handleInputChange = useCallback(
168→    (e: React.ChangeEvent<HTMLInputElement>) => {
169→      setQuery(e.target.value);
170→      if (!open) {
171→        setOpen(true);
172→      }
173→    },
174→    [open],
175→  );
176→
177→  const handleInputFocus = useCallback(() => {
178→    if (availableOptions.length > 0) {
179→      setOpen(true);
180→    }
181→  }, [availableOptions.length]);
182→
183→  const getOptionLabel = useCallback(
184→    (optionValue: string) =>
185→      options.find(o => o.value === optionValue)?.label ?? optionValue,
186→    [options],
187→  );
188→
189→  const activeOptionId =
190→    open && availableOptions[activeIndex]
191→      ? `${listboxId}-option-${activeIndex}`
192→      : undefined;
193→
194→  return (
195→    <FormField
196→      label={label}
197→      description={description}
198→      error={error}
199→      htmlFor={id}
200→    >
201→      <div className="form-tag-picker" ref={containerRef}>
202→        <div
203→          className="form-tag-picker__input-area"
204→          onClick={() => inputRef.current?.focus()}
205→        >
206→          {value.map(v => (
207→            <span key={v} className="form-tag-picker__tag">
208→              <span className="form-tag-picker__tag-label">
209→                {getOptionLabel(v)}
210→              </span>
211→              <button
212→                type="button"
213→                className="form-tag-picker__tag-remove"
214→                onClick={e => {
215→                  e.stopPropagation();
216→                  removeTag(v);
217→                }}
218→                aria-label={`Remove ${getOptionLabel(v)}`}
219→              >
220→                <svg width="8" height="8" viewBox="0 0 8 8" fill="none">
221→                  <path
222→                    d="M1 1L7 7M7 1L1 7"
223→                    stroke="currentColor"
224→                    strokeWidth="1.5"
225→                    strokeLinecap="round"
226→                  />
227→                </svg>
228→              </button>
229→            </span>
230→          ))}
231→          <input
232→            id={id}
233→            ref={inputRef}
234→            className="form-tag-picker__input"
235→            type="text"
236→            value={query}
237→            onChange={handleInputChange}
238→            onFocus={handleInputFocus}
239→            onKeyDown={handleKeyDown}
240→            placeholder={value.length === 0 ? placeholder : undefined}
241→            autoFocus={autoFocus}
242→            spellCheck={false}
243→            autoComplete="off"
244→            role="combobox"
245→            aria-expanded={open}
246→            aria-controls={open ? listboxId : undefined}
247→            aria-activedescendant={activeOptionId}
248→            aria-invalid={error ? true : undefined}
249→            aria-describedby={error ? `${id}-error` : undefined}
250→          />
251→        </div>
252→        {open && availableOptions.length > 0 && (
253→          <ul
254→            id={listboxId}
255→            ref={menuRef}
256→            className="form-tag-picker__menu"
257→            role="listbox"
258→          >
259→            {availableOptions.map((opt, i) => (
260→              <li
261→                key={opt.value}
262→                id={`${listboxId}-option-${i}`}
263→                className={`form-tag-picker__option${i === activeIndex ? ' form-tag-picker__option--active' : ''}`}
264→                role="option"
265→                aria-selected={i === activeIndex}
266→                data-active={i === activeIndex}
267→                onMouseEnter={() => setActiveIndex(i)}
268→                onMouseDown={e => {
269→                  e.preventDefault();
270→                  selectOption(opt.value);
271→                }}
272→              >
273→                {opt.label}
274→              </li>
275→            ))}
276→          </ul>
277→        )}
278→      </div>
279→    </FormField>
280→  );
281→}
